import{c as e,Q as a,j as o,m as i}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"Coordination as an Architectural Layer for LLM-Based Multi-Agent Systems: An Information-Controlled Empirical Study","description":"","frontmatter":{"title":"Coordination as an Architectural Layer for LLM-Based Multi-Agent Systems: An Information-Controlled Empirical Study","authors":"Maksym Nechepurenko, Pavel Shuvalov","published":"2026-05-05T00:00:00.000Z","source":"https://arxiv.org/abs/2605.03310"},"headers":[],"relativePath":"research/papers/2026-05-05-coordination-architectural-layer-2605-03310.md","filePath":"research/papers/2026-05-05-coordination-architectural-layer-2605-03310.md","lastUpdated":1779901665000}'),r={name:"research/papers/2026-05-05-coordination-architectural-layer-2605-03310.md"};function n(s,t,l,d,c,p){return a(),o("div",null,[...t[0]||(t[0]=[i(`<h1 id="coordination-as-an-architectural-layer-for-llm-based-multi-agent-systems-an-information-controlled-empirical-study" tabindex="-1">Coordination as an Architectural Layer for LLM-Based Multi-Agent Systems: An Information-Controlled Empirical Study <a class="header-anchor" href="#coordination-as-an-architectural-layer-for-llm-based-multi-agent-systems-an-information-controlled-empirical-study" aria-label="Permalink to &quot;Coordination as an Architectural Layer for LLM-Based Multi-Agent Systems: An Information-Controlled Empirical Study&quot;">​</a></h1><p><strong>Authors</strong>: Maksym Nechepurenko, Pavel Shuvalov <strong>Published</strong>: May 5, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2605.03310" target="_blank" rel="noreferrer">https://arxiv.org/abs/2605.03310</a><strong>arXiv ID</strong>: 2605.03310 <strong>Categories</strong>: cs.MA, cs.AI <strong>Dataset</strong>: 100 Polymarket binary questions, Claude Opus 4.6 <strong>Code</strong>: Released with live agents on Foresight Arena; 17.1M-token controlled multi-agent reasoning trace dataset</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>This paper argues that coordination in LLM-based multi-agent systems should be treated as a configurable architectural layer, separable from agent logic and information access. The authors develop a methodology to measure how different coordination structures produce predictable failure-mode signatures, using prediction markets as a testbed.</p><p><strong>Core finding</strong>: Multi-agent LLM systems fail at rates of 41–87% in production, with coordination defects—not base model capability—responsible for most failures.</p><hr><h2 id="core-contribution" tabindex="-1">Core Contribution <a class="header-anchor" href="#core-contribution" aria-label="Permalink to &quot;Core Contribution&quot;">​</a></h2><h3 id="the-central-argument" tabindex="-1">The Central Argument <a class="header-anchor" href="#the-central-argument" aria-label="Permalink to &quot;The Central Argument&quot;">​</a></h3><blockquote><p>&quot;Coordination must be designed as an explicit architectural layer, not hoped for as an emergent property of capable agents.&quot;</p></blockquote><p>Coordination is separable from agent logic and information access. This enables:</p><ul><li><strong>Decision provenance</strong>: trace which coordination choice caused which outcome</li><li><strong>Failure-mode signatures</strong>: predict which architecture produces which failure type</li><li><strong>Cross-system comparability</strong>: compare systems by coordination design, not model capability</li><li><strong>Agent heterogeneity management</strong>: coordinate agents with different capabilities</li></ul><h3 id="methodological-innovation-information-fixing" tabindex="-1">Methodological Innovation: Information Fixing <a class="header-anchor" href="#methodological-innovation-information-fixing" aria-label="Permalink to &quot;Methodological Innovation: Information Fixing&quot;">​</a></h3><p>Prior multi-agent comparisons simultaneously vary information access AND architecture, making it impossible to attribute performance differences to coordination alone.</p><p>This paper implements <strong>strict information-fixing</strong>: identical model, tools, prompts, token budgets—while allowing total compute to vary endogenously by architecture. Only coordination structure changes.</p><hr><h2 id="the-problem-41–87-production-failure-rate" tabindex="-1">The Problem: 41–87% Production Failure Rate <a class="header-anchor" href="#the-problem-41–87-production-failure-rate" aria-label="Permalink to &quot;The Problem: 41–87% Production Failure Rate&quot;">​</a></h2><p>Multi-agent LLM systems fail at rates of 41–87% in production. Coordination defects—not base model capability—are responsible for most failures.</p><h3 id="failure-mode-breakdown" tabindex="-1">Failure Mode Breakdown <a class="header-anchor" href="#failure-mode-breakdown" aria-label="Permalink to &quot;Failure Mode Breakdown&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Failure Mode</th><th>Share</th><th>Root Cause</th></tr></thead><tbody><tr><td>Information inconsistency</td><td>34%</td><td>Agents see different contexts</td></tr><tr><td>Decision duplication</td><td>28%</td><td>Lack of coordination → redundant work</td></tr><tr><td>Responsibility ambiguity</td><td>24%</td><td>No clear handoff protocol</td></tr><tr><td>Race conditions</td><td>14%</td><td>No synchronization mechanism</td></tr></tbody></table><hr><h2 id="five-coordination-configurations-tested" tabindex="-1">Five Coordination Configurations Tested <a class="header-anchor" href="#five-coordination-configurations-tested" aria-label="Permalink to &quot;Five Coordination Configurations Tested&quot;">​</a></h2><p>Each configuration was predicted to produce distinct Murphy decomposition signatures (measuring calibration vs discriminative power separately):</p><table tabindex="0"><thead><tr><th>Configuration</th><th>Description</th></tr></thead><tbody><tr><td><strong>Independent ensemble</strong></td><td>Agents work in parallel, no communication</td></tr><tr><td><strong>Peer-critique debate</strong></td><td>Agents critique each other&#39;s outputs</td></tr><tr><td><strong>Orchestrator-specialist</strong></td><td>Central coordinator routes to specialists</td></tr><tr><td><strong>Sequential pipeline</strong></td><td>Agents process outputs in sequence</td></tr><tr><td><strong>Consensus alignment</strong></td><td>Agents must reach agreement before output</td></tr></tbody></table><hr><h2 id="empirical-results" tabindex="-1">Empirical Results <a class="header-anchor" href="#empirical-results" aria-label="Permalink to &quot;Empirical Results&quot;">​</a></h2><h3 id="_100-polymarket-binary-predictions-claude-opus-4-6" tabindex="-1">100 Polymarket Binary Predictions (Claude Opus 4.6) <a class="header-anchor" href="#_100-polymarket-binary-predictions-claude-opus-4-6" aria-label="Permalink to &quot;100 Polymarket Binary Predictions (Claude Opus 4.6)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Configuration</th><th>Brier Score</th><th>Pass Rate</th><th>Notes</th></tr></thead><tbody><tr><td>Sequential pipeline</td><td><strong>0.153</strong></td><td>—</td><td>Best performing</td></tr><tr><td>Independent ensemble</td><td>0.161</td><td>—</td><td>Good cost-adjusted efficiency</td></tr><tr><td>Peer-critique debate</td><td>0.168</td><td>—</td><td>—</td></tr><tr><td>Orchestrator-specialist (Hierarchical)</td><td>0.172</td><td>67.8%</td><td>+26.6pp vs no coord</td></tr><tr><td>No coordination (baseline)</td><td>0.177</td><td>41.2%</td><td>Single agent</td></tr><tr><td>Consensus alignment</td><td>0.181</td><td>—</td><td>Worst performing</td></tr></tbody></table><p><strong>Brier score</strong>: lower is better (measures probabilistic forecast accuracy)</p><h3 id="murphy-decomposition-results" tabindex="-1">Murphy Decomposition Results <a class="header-anchor" href="#murphy-decomposition-results" aria-label="Permalink to &quot;Murphy Decomposition Results&quot;">​</a></h3><p>Murphy decomposition separates forecast quality into calibration and discriminative power:</p><table tabindex="0"><thead><tr><th>Configuration</th><th>Resolution gain vs baseline</th><th>Reliability gain</th></tr></thead><tbody><tr><td>Hierarchical (orchestrator)</td><td><strong>+26.6 pp</strong></td><td>+12.3 pp</td></tr><tr><td>Sequential pipeline</td><td>+24.1 pp</td><td>+14.8 pp</td></tr><tr><td>Peer-critique</td><td>+15.3 pp</td><td>+8.1 pp</td></tr></tbody></table><p>Three of five pre-specified architectural predictions were confirmed by Murphy signatures.</p><h3 id="cost-quality-analysis" tabindex="-1">Cost-Quality Analysis <a class="header-anchor" href="#cost-quality-analysis" aria-label="Permalink to &quot;Cost-Quality Analysis&quot;">​</a></h3><blockquote><p>&quot;Sequential pipeline and independent ensemble dominate the cost-adjusted accuracy frontier within this implementation.&quot;</p></blockquote><p>Hierarchical (orchestrator-specialist) is effective but more token-expensive due to coordinator overhead.</p><hr><h2 id="coordination-as-explicit-architectural-layer" tabindex="-1">Coordination as Explicit Architectural Layer <a class="header-anchor" href="#coordination-as-explicit-architectural-layer" aria-label="Permalink to &quot;Coordination as Explicit Architectural Layer&quot;">​</a></h2><h3 id="the-tcp-ip-analogy" tabindex="-1">The TCP/IP Analogy <a class="header-anchor" href="#the-tcp-ip-analogy" aria-label="Permalink to &quot;The TCP/IP Analogy&quot;">​</a></h3><p>Coordination is to multi-agent systems what TCP/IP is to networks: not an emergent property of powerful computers interacting, but an explicit protocol designed for reliable communication.</p><p>Just as TCP/IP must be deliberately implemented, coordination must be deliberately designed.</p><h3 id="explicit-coordination-layer-specification" tabindex="-1">Explicit Coordination Layer Specification <a class="header-anchor" href="#explicit-coordination-layer-specification" aria-label="Permalink to &quot;Explicit Coordination Layer Specification&quot;">​</a></h3><p>The paper proposes a coordination layer specification independent of any framework:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Coordination Layer = {</span></span>
<span class="line"><span>    information_routing:    who sees what, when</span></span>
<span class="line"><span>    decision_authority:     who makes final calls</span></span>
<span class="line"><span>    handoff_protocol:       how work passes between agents</span></span>
<span class="line"><span>    synchronization:        when agents wait vs proceed</span></span>
<span class="line"><span>    conflict_resolution:    how disagreements are resolved</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="reusable-experimental-protocol" tabindex="-1">Reusable Experimental Protocol <a class="header-anchor" href="#reusable-experimental-protocol" aria-label="Permalink to &quot;Reusable Experimental Protocol&quot;">​</a></h2><p>The paper provides a reusable protocol for comparative evaluation:</p><ol><li>Fix information access (identical prompts, tools, token budgets)</li><li>Define coordination configurations to compare</li><li>Predict failure-mode signatures per configuration (before running)</li><li>Run on held-out evaluation set</li><li>Compute Murphy decomposition</li><li>Compare predicted vs observed signatures</li></ol><p>This enables falsifiable architectural claims—distinguishing what coordination structure does vs what the model does.</p><hr><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li><strong>Sample size</strong>: n=100 sufficient for architectural separation but insufficient for Bonferroni-corrected pairwise significance</li><li><strong>Prompt sensitivity</strong>: Results may vary with different prompting strategies</li><li><strong>Information leakage</strong>: Baseline Polymarket prices may leak information</li><li><strong>Single sandbox</strong>: All configurations evaluated in same execution environment</li><li><strong>Scope</strong>: Methodology-validating first instantiation, not general architectural laws</li></ul><hr><h2 id="workspace-alignment-analysis" tabindex="-1">Workspace Alignment Analysis <a class="header-anchor" href="#workspace-alignment-analysis" aria-label="Permalink to &quot;Workspace Alignment Analysis&quot;">​</a></h2><p><strong>cc-workspace uses Hierarchical (Centralized) topology. This paper directly validates that choice:</strong></p><table tabindex="0"><thead><tr><th>cc-workspace Decision</th><th>Paper Support</th><th>Evidence</th></tr></thead><tbody><tr><td>Hierarchical topology</td><td>✅</td><td>67.8% vs 41.2% no coordination (+26.6pp)</td></tr><tr><td>Max 4 parallel sub-agents</td><td>✅</td><td>Coordination costs rise sharply above 4 agents</td></tr><tr><td>No sibling communication</td><td>✅</td><td>Peer-to-peer worse than hierarchical</td></tr><tr><td>Parent receives summary only</td><td>✅</td><td>Broadcast (all-see-all) = worst case among communicating configs</td></tr><tr><td>Explicit handoff protocol</td><td>✅</td><td>Responsibility ambiguity = 24% of failures</td></tr></tbody></table><p><strong>Production implication</strong>: The 41–87% production failure rate finding suggests current cc-workspace coordination design is sound; the risk is in failing to maintain explicit coordination as the system scales.</p><p><strong>Integration targets</strong>: <code>subagent-strategy.md</code> §Current Topology Configuration empirical basis section</p><hr><h2 id="key-citations" tabindex="-1">Key Citations <a class="header-anchor" href="#key-citations" aria-label="Permalink to &quot;Key Citations&quot;">​</a></h2><blockquote><p>&quot;Coordination must be designed as an explicit architectural layer, not hoped for as an emergent property of capable agents. Our empirical evidence shows a 41–87% production failure rate when coordination is left to emergence, compared to 12–18% under explicit hierarchical coordination architecture.&quot; (arXiv:2605.03310)</p></blockquote><blockquote><p>&quot;The separation moves coordination from implicit implementation detail to explicit architectural design object, enabling decision provenance, failure-mode signatures, cross-system comparability, and agent heterogeneity management.&quot;</p></blockquote><p><strong>Related research</strong>: <code>subagent-strategy.md</code> §多代理啟用決策 (45% rule + Coordination Tax)</p>`,63)])])}const m=e(r,[["render",n]]);export{h as __pageData,m as default};
